(function(w){"use strict";const ID="leap-year";function compute(x){const y=Number(x.year);if(!Number.isInteger(y)||y<1||y>9999)return{error:"1~9999 사이의 연도를 입력해 주세요."};return{isLeap:y%400===0||(y%4===0&&y%100!==0),days:(y%400===0||(y%4===0&&y%100!==0))?366:365}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><div class="hm-calc-field"><label>연도</label><input class="hm-calc-input" inputmode="numeric" placeholder="예: 2028"></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">윤년 확인</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const input=root.querySelector("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const r=compute({year:Number(input.value)});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}api.setMessage(msg,"");api.setResult(res,api.resultCard("윤년 판정",r.isLeap?'윤년입니다':'평년입니다',`${r.days}일`));});}
w.HM_CALC.register(ID,{compute,render});})(window);
